<template>
  <div class="content flex-space-between">
    <div class="left g-page-container-with-header">
      <div class="container-header flex-space-between">
        <span class="title">Topic列表</span>
        <div class="g-button" @click="handleUpdate">全部更新</div>
      </div>
      <div class="container-content">
        <div class="g-table">
          <!-- 表头 -->
          <div class="cell flex-space-between header">
            <div
              v-for="(label, index) in labels"
              :key="index"
              class="name bg"
              :class="label.class"
            >
              {{ label.text }}
            </div>
            <div class="name bg refresh opacity-0">占位</div>
          </div>

          <!-- 数据行 -->
          <div
            v-for="(item, index) in paginatedData"
            :key="index"
            class="cell flex-space-between"
            :class="{ selected: selectedIndex === index }"
            @click="handleRowClick(index, item)"
          >
            <div class="name topicid">
              {{ (currentPage - 1) * pageSize + index + 1 }}
            </div>
            <div class="name topic-name">{{ item.name }}</div>
            <div class="name timestamp">
              {{ formatTimestamp(item.timestamp) }}
            </div>
            <div class="name refresh" @click.stop="handleRefreshRow(item)">
              更新
            </div>
          </div>
        </div>
        <pagination :total="topicData.length" @change="handlePageChange" />
      </div>
    </div>

    <div class="right g-page-container-with-header">
      <div class="container-header">
        <span class="title">Topic数据</span>
      </div>
      <div class="container-content">
        <div class="list flex-direction-column">
          <pre class="item">{{ selectedData }}</pre>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useCommand } from '@/hooks/useCommand.js'
import { useDataMerge } from '@/hooks/useDataMerge'

import { useTimeFormat } from '@/hooks/useTimeFormat'
const { formatTimestamp } = useTimeFormat()

// store相关
const store = useWslStore()
const { received, isConnected } = storeToRefs(store)
const { sendGetStatusData } = useCommand(store)

// 表头配置
const labels = [
  { text: 'Topic ID', class: 'topicid' },
  { text: 'Topic 名称', class: 'topic-name' },
  { text: '时间', class: 'timestamp' }
]

// 选中状态
const selectedIndex = ref(null)
const selectedData = ref('')

// 数据相关，保持13和61命令的兼容
// 计算要显示的数据，合并13和61命令的数据
const topicData = useDataMerge(
  computed(() => received.value?.statusData?.topicDataList),
  { idField: 'name' } // topic 用 name 作为标识
).mergedData

// 选中行数据的自动更新
// 这里的 topicData 已经处理好了所有数据合并逻辑
watch(
  () => topicData.value,
  () => {
    // 如果有选中的行，更新它的数据
    if (selectedIndex.value !== null) {
      const currentItem = paginatedData.value[selectedIndex.value]
      if (currentItem) {
        selectedData.value = currentItem.data || ''
      }
    }
  }
)

// 等socket连接后发送13命令获取数据
watch(
  () => isConnected.value,
  (newStatus) => {
    if (newStatus) {
      sendGetStatusData('topic')
    }
  },
  { immediate: true }
)

// 分页相关
const pageSize = ref(10)
const currentPage = ref(1)

const paginatedData = computed(() => {
  const start = (currentPage.value - 1) * pageSize.value
  const end = start + pageSize.value
  return topicData.value.slice(start, end)
})

const handlePageChange = (val) => {
  currentPage.value = val.page
  pageSize.value = val.size
  selectedIndex.value = null
  selectedData.value = ''
}

// 点击行处理
const handleRowClick = (index, item) => {
  selectedIndex.value = index
  selectedData.value = item.data || ''
}

// 全部更新处理
const handleUpdate = () => {
  sendGetStatusData('topic')
}

// 单行刷新处理
const handleRefreshRow = (item) => {
  if (item.name) {
    // 改为检查 name 而不是 devid
    sendGetStatusData('topic', item.name) // 直接传入 topic name
  } else {
    console.warn('该项没有 name:', item)
  }
}
</script>

<style lang="less" scoped>
.content {
  .left {
    width: 60%;
    align-self: flex-start;
  }

  .right {
    flex: 1;
    align-self: flex-start;
    margin-left: 20px;

    .list {
      .item {
        font-family: 'OPPOSans', sans-serif;
        color: #186c3c;
      }
    }
  }

  .name {
    &.topicid {
      width: 8rem;
    }
    &.topic-name {
      width: 8rem;
    }
    &.timestamp {
      width: 11rem;
    }
    &.refresh {
      width: 5rem;
      &.opacity-0 {
        opacity: 0;
      }
    }
  }
}
</style>
